class TerminalManager
  DATA_DIR    = ENV.fetch("SANDCASTLE_DATA_DIR", "/data")
  NETWORK_NAME = "sandcastle-web"
  DYNAMIC_DIR  = File.join(DATA_DIR, "traefik", "dynamic")

  TMUX_PORT  = 7681
  SHELL_PORT = 7682

  class Error < StandardError; end

  # Opens a web terminal for the given sandbox.
  # type: "tmux" (default) or "shell"
  # Writes Traefik config (idempotent) and returns the terminal URL.
  def open(sandbox:, type: "tmux")
    raise Error, "Sandbox is not running" unless sandbox.status == "running"

    write_traefik_config(sandbox)
    terminal_url(sandbox, type)
  end

  # Returns true if ttyd is listening on the appropriate port inside the sandbox container.
  # Uses docker exec + ss to check from inside the container — works in both dev (host Rails)
  # and production (Rails in Docker) without needing Docker network hostname resolution.
  def active?(sandbox:, type: "tmux")
    return false if sandbox.container_id.blank?

    port = type == "shell" ? SHELL_PORT : TMUX_PORT
    container = Docker::Container.get(sandbox.container_id)
    _out, _err, code = container.exec([ "sh", "-c", "ss -tlnp 2>/dev/null | grep -q ':#{port}' || netstat -tlnp 2>/dev/null | grep -q ':#{port}'" ])
    code == 0
  rescue Docker::Error::NotFoundError, Docker::Error::DockerError => e
    Rails.logger.debug("TerminalManager#active? #{sandbox.full_name}:#{port} → #{e.class}: #{e.message}")
    false
  end

  # Deletes the Traefik config for the given sandbox.
  def close(sandbox:)
    delete_traefik_config(sandbox)
  end

  # Scans terminal-*.yml files; removes configs for sandboxes that no longer exist or aren't running.
  def cleanup_orphaned
    Dir.glob(File.join(DYNAMIC_DIR, "terminal-*.yml")).each do |path|
      match = File.basename(path).match(/\Aterminal-(\d+)\.yml\z/)
      next unless match

      sandbox_id = match[1].to_i
      sandbox = Sandbox.find_by(id: sandbox_id)

      if sandbox.nil? || sandbox.status != "running"
        File.delete(path)
        Rails.logger.info("TerminalManager: removed orphaned Traefik config #{File.basename(path)}")
      end
    end
  end

  private

  def terminal_url(sandbox, type)
    "/terminal/#{sandbox.id}/#{type}"
  end

  def write_traefik_config(sandbox)
    FileUtils.mkdir_p(DYNAMIC_DIR)
    config_path = File.join(DYNAMIC_DIR, "terminal-#{sandbox.id}.yml")
    return if File.exist?(config_path)

    host = ENV.fetch("SANDCASTLE_HOST", "localhost")
    id   = sandbox.id
    container = sandbox.full_name

    if ENV["SANDCASTLE_TLS_MODE"] == "selfsigned"
      tmux_rule  = "HostRegexp(`.+`) && PathPrefix(`/terminal/#{id}/tmux`)"
      shell_rule = "HostRegexp(`.+`) && PathPrefix(`/terminal/#{id}/shell`)"
    else
      tmux_rule  = "Host(`#{host}`) && PathPrefix(`/terminal/#{id}/tmux`)"
      shell_rule = "Host(`#{host}`) && PathPrefix(`/terminal/#{id}/shell`)"
    end

    config = {
      "http" => {
        "routers" => {
          "terminal-#{id}-tmux" => {
            "rule"        => tmux_rule,
            "service"     => "terminal-#{id}-tmux",
            "entryPoints" => [ "websecure" ],
            "tls"         => tls_config,
            "middlewares" => [ "terminal-auth-#{id}", "terminal-#{id}-strip-tmux" ],
            "priority"    => 100
          },
          "terminal-#{id}-shell" => {
            "rule"        => shell_rule,
            "service"     => "terminal-#{id}-shell",
            "entryPoints" => [ "websecure" ],
            "tls"         => tls_config,
            "middlewares" => [ "terminal-auth-#{id}", "terminal-#{id}-strip-shell" ],
            "priority"    => 100
          }
        },
        "middlewares" => {
          "terminal-auth-#{id}" => {
            "forwardAuth" => {
              "address"            => "http://sandcastle-web:80/terminal/auth",
              "trustForwardHeader" => true
            }
          },
          "terminal-#{id}-strip-tmux" => {
            "stripPrefix" => { "prefixes" => [ "/terminal/#{id}/tmux" ] }
          },
          "terminal-#{id}-strip-shell" => {
            "stripPrefix" => { "prefixes" => [ "/terminal/#{id}/shell" ] }
          }
        },
        "services" => {
          "terminal-#{id}-tmux" => {
            "loadBalancer" => {
              "servers" => [ { "url" => "http://#{container}:#{TMUX_PORT}" } ]
            }
          },
          "terminal-#{id}-shell" => {
            "loadBalancer" => {
              "servers" => [ { "url" => "http://#{container}:#{SHELL_PORT}" } ]
            }
          }
        }
      }
    }

    File.write(config_path, config.to_yaml)
  end

  def tls_config
    case ENV["SANDCASTLE_TLS_MODE"]
    when "selfsigned", "mkcert"
      {}
    else
      { "certResolver" => "letsencrypt" }
    end
  end

  def delete_traefik_config(sandbox)
    path = File.join(DYNAMIC_DIR, "terminal-#{sandbox.id}.yml")
    File.delete(path) if File.exist?(path)
  end
end

class VncManager
  DATA_DIR    = ENV.fetch("SANDCASTLE_DATA_DIR", "/data")
  DYNAMIC_DIR = File.join(DATA_DIR, "traefik", "dynamic")

  class Error < StandardError; end

  # Opens a web-based VNC session for the given sandbox.
  # Returns the URL path to the noVNC session.
  # websockify runs inside the sandbox container (started by entrypoint.sh),
  # so we only need to connect the sandbox to the Traefik network and write
  # the Traefik routing config.
  def open(sandbox:)
    raise Error, "Sandbox is not running" unless sandbox.status == "running"

    write_traefik_config(sandbox)
    vnc_url(sandbox)
  end

  # Closes the web VNC session for the given sandbox.
  def close(sandbox:)
    delete_traefik_config(sandbox)
  rescue Docker::Error::DockerError => e
    Rails.logger.error("VncManager: close failed for #{sandbox.full_name}: #{e.message}")
  end

  # Returns true if the sandbox's websockify process is accepting connections.
  # Requires the sandbox to already be connected to the sandcastle-web network
  # (i.e., after open has been called).
  def active?(sandbox:)
    return false unless File.exist?(traefik_config_path(sandbox))

    TCPSocket.new(sandbox.full_name, 6080).close
    true
  rescue Errno::ECONNREFUSED, Errno::ETIMEDOUT, SocketError
    false
  end

  # Removes orphaned Traefik VNC configs whose sandbox is gone or not running.
  def cleanup_orphaned
    Dir.glob(File.join(DYNAMIC_DIR, "vnc-*.yml")).each do |path|
      id = path.match(/vnc-(\d+)\.yml/)&.[](1)&.to_i
      next unless id

      sandbox = Sandbox.find_by(id: id)
      if sandbox.nil? || sandbox.status != "running"
        File.delete(path)
        Rails.logger.info("VncManager: removed orphaned Traefik config #{File.basename(path)}")
      end
    end
  rescue => e
    Rails.logger.error("VncManager: orphan cleanup failed: #{e.message}")
  end

  def prepare_traefik_config(sandbox)
    write_traefik_config(sandbox)
  end

  def vnc_url(sandbox)
    id = sandbox.id
    "/novnc/vnc.html?path=/vnc/#{id}/websockify&autoconnect=true"
  end

  private

  def traefik_config_path(sandbox)
    File.join(DYNAMIC_DIR, "vnc-#{sandbox.id}.yml")
  end

  def write_traefik_config(sandbox)
    FileUtils.mkdir_p(DYNAMIC_DIR)
    config_path = traefik_config_path(sandbox)
    return if File.exist?(config_path)

    host = ENV.fetch("SANDCASTLE_HOST", "localhost")
    id = sandbox.id
    sandbox_name = sandbox.full_name

    base_rule = if ENV["SANDCASTLE_TLS_MODE"] == "selfsigned"
      "HostRegexp(`.+`) && PathPrefix(`/vnc/#{id}/websockify`)"
    else
      "Host(`#{host}`) && PathPrefix(`/vnc/#{id}/websockify`)"
    end

    # Route only the WebSocket path /vnc/{id}/websockify to websockify-go on port 6080.
    # noVNC static files (vnc.html, core/, etc.) are served from Rails public/novnc/.
    # stripPrefix removes /vnc/{id} so websockify-go receives /websockify.
    config = {
      "http" => {
        "routers" => {
          "vnc-#{id}" => {
            "rule" => base_rule,
            "service" => "vnc-#{id}",
            "entryPoints" => [ "websecure" ],
            "tls" => tls_config,
            "middlewares" => [ "vnc-auth-#{id}", "vnc-stripprefix-#{id}" ],
            "priority" => 100
          }
        },
        "middlewares" => {
          "vnc-auth-#{id}" => {
            "forwardAuth" => {
              "address" => "http://sandcastle-web:80/vnc/auth",
              "trustForwardHeader" => true
            }
          },
          "vnc-stripprefix-#{id}" => {
            "stripPrefix" => {
              "prefixes" => [ "/vnc/#{id}" ]
            }
          }
        },
        "services" => {
          "vnc-#{id}" => {
            "loadBalancer" => {
              "servers" => [ { "url" => "http://#{sandbox_name}:6080" } ]
            }
          }
        }
      }
    }

    File.write(config_path, config.to_yaml)
  end

  def tls_config
    case ENV["SANDCASTLE_TLS_MODE"]
    when "selfsigned", "mkcert"
      {}
    else
      { "certResolver" => "letsencrypt" }
    end
  end

  def delete_traefik_config(sandbox)
    path = traefik_config_path(sandbox)
    File.delete(path) if File.exist?(path)
  end
end

